package cn.edu.agent.tool.impl;

import cn.edu.agent.tool.AgentTool;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.Map;

public class BashTool implements AgentTool {
    @Override
    public String getName() {
        return "bash";
    }

    @Override
    public String getDescription() {
        return "执行 Windows 命令行 (cmd) 指令。可以用来查看目录、读写文件等。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        // 按照 Anthropic 的 JSON Schema 格式定义参数
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "command", Map.of("type", "string", "description", "要执行的 cmd 命令")
                ),
                "required", new String[]{"command"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) throws Exception {
        String command = (String) input.get("command");
        System.out.println("\n[BashTool] 🤖 执行命令: " + command);

        ProcessBuilder pb = new ProcessBuilder("cmd.exe", "/c", command);
        pb.redirectErrorStream(true); // 合并正确和错误输出
        Process process = pb.start();

        // Windows 下 cmd 的输出通常是 GBK 编码
        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream(), "GBK"));
        StringBuilder output = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            output.append(line).append("\n");
        }
        process.waitFor(); // 等待命令执行完

        String result = output.toString().trim();
        return result.isEmpty() ? "命令执行成功，无输出。" : result;
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.tool.AgentTool;

import java.util.LinkedHashMap;
import java.util.Map;

/**
 * CompactTool — Layer 3 压缩工具
 * LLM 感觉上下文过长时可主动调用此工具。
 * execute() 本身不做压缩，只返回标记字符串 "__COMPACT__"，
 * AgentLoop 检测到该标记后调用 ContextCompactor.autoCompact()。
 */
public class CompactTool implements AgentTool {

    public static final String COMPACT_SIGNAL = "__COMPACT__";

    @Override
    public String getName() {
        return "compact";
    }

    @Override
    public String getDescription() {
        return "当你感觉对话历史过长、影响思考效率时，主动调用此工具压缩上下文。" +
                "压缩后历史将被摘要替换，但完整记录已落盘保存。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        Map<String, Object> schema = new LinkedHashMap<>();
        schema.put("type", "object");

        Map<String, Object> properties = new LinkedHashMap<>();
        Map<String, Object> reasonProp = new LinkedHashMap<>();
        reasonProp.put("type", "string");
        reasonProp.put("description", "触发压缩的原因（可选，用于日志）");
        properties.put("reason", reasonProp);

        schema.put("properties", properties);
        schema.put("required", new String[]{});
        return schema;
    }

    @Override
    public String execute(Map<String, Object> input) {
        // 记录触发原因（如有）
        if (input != null && input.containsKey("reason")) {
            System.out.println("🗜️ LLM 主动触发压缩，原因: " + input.get("reason"));
        } else {
            System.out.println("🗜️ LLM 主动触发压缩");
        }
        // 返回标记，由 AgentLoop 检测并执行真正的压缩
        return COMPACT_SIGNAL;
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.tool.AgentTool;
import cn.edu.agent.tool.utils.WorkspaceEnv;

import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Map;

/**
 * EditFile 工具 - 编辑文件内容
 */
public class EditFileTool implements AgentTool {

    @Override
    public String getName() {
        return "edit_file";
    }

    @Override
    public String getDescription() {
        return "编辑文件内容。用新文本替换旧文本。只替换第一次匹配的内容。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "path", Map.of(
                                "type", "string",
                                "description", "要编辑的文件路径"
                        ),
                        "old_text", Map.of(
                                "type", "string",
                                "description", "要替换的旧文本"
                        ),
                        "new_text", Map.of(
                                "type", "string",
                                "description", "新文本"
                        )
                ),
                "required", new String[]{"path", "old_text", "new_text"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) throws Exception {
        String path = (String) input.get("path");
        String oldText = (String) input.get("old_text");
        String newText = (String) input.get("new_text");

        if (path == null || path.trim().isEmpty()) {
            return " 错误: 必须指定文件路径";
        }

        if (oldText == null || oldText.trim().isEmpty()) {
            return " 错误: 必须指定要替换的旧文本";
        }

        if (newText == null) {
            return " 错误: 必须指定新文本";
        }

        System.out.println("\n[EditFileTool] ✏  编辑文件: " + path);
        System.out.println("   工作目录: " + WorkspaceEnv.WORKDIR);
        System.out.println("   旧文本长度: " + oldText.length() + " 字符");
        System.out.println("   新文本长度: " + newText.length() + " 字符");

        try {
            // 使用 WorkspaceEnv 的 safePath
            Path safePath = WorkspaceEnv.safePath(path.trim());

            // 读取文件内容
            String content = Files.readString(safePath, StandardCharsets.UTF_8);

            // 查找并替换文本
            if (!content.contains(oldText)) {
                return " 错误: 文件中找不到指定的旧文本\n" +
                        "旧文本: " + oldText.substring(0, Math.min(50, oldText.length())) + "...";
            }

            // 只替换第一次匹配
            String newContent = content.replaceFirst(java.util.regex.Pattern.quote(oldText),
                    java.util.regex.Matcher.quoteReplacement(newText));

            // 写回文件
            Files.writeString(safePath, newContent, StandardCharsets.UTF_8);

            System.out.println(" 文件编辑成功");
            return " 文件已成功编辑: " + path;

        } catch (IllegalArgumentException e) {
            return " 安全错误: " + e.getMessage();
        } catch (Exception e) {
            return " 编辑文件失败: " + e.getMessage();
        }
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.skill.SkillLoader;
import cn.edu.agent.tool.AgentTool;
import lombok.RequiredArgsConstructor;

import java.util.Map;

@RequiredArgsConstructor
public class LoadSkillTool implements AgentTool {

    private final SkillLoader skillLoader;

    @Override
    public String getName() {
        return "load_skill";
    }

    @Override
    public String getDescription() {
        return "Load specialized knowledge by skill name before tackling unfamiliar topics.";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "name", Map.of("type", "string", "description", "Skill name to load")
                ),
                "required", new String[]{"name"}
        );
    }

