        return skillLoader.getContent(name);
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.tool.AgentTool;
import cn.edu.agent.tool.utils.WorkspaceEnv;

import java.io.FileNotFoundException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Map;

/**
 * ReadFile 工具 - 安全读取文件
 */
public class ReadFileTool implements AgentTool {

    @Override
    public String getName() {
        return "read_file";
    }

    @Override
    public String getDescription() {
        return "安全地读取文件内容。支持限制读取行数，防止读取过大文件。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "path", Map.of(
                                "type", "string",
                                "description", "要读取的文件路径"
                        ),
                        "limit", Map.of(
                                "type", "integer",
                                "description", "最大读取行数（可选，默认读取全部）"
                        )
                ),
                "required", new String[]{"path"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) throws Exception {
        String path = (String) input.get("path");
        Integer limit = (Integer) input.get("limit");

        if (path == null || path.trim().isEmpty()) {
            return "❌ 错误: 必须指定文件路径";
        }

        System.out.println("\n[ReadFileTool] 📖 读取文件: " + path);
        System.out.println("   工作目录: " + WorkspaceEnv.WORKDIR);

        try {
            // 使用 WorkspaceEnv 的 safePath
            Path safePath = WorkspaceEnv.safePath(path.trim());

            // 读取文件内容
            String content = Files.readString(safePath, StandardCharsets.UTF_8);

            // 限制行数
            if (limit != null && limit > 0) {
                String[] lines = content.split("\n");
                int maxLines = Math.min(limit, lines.length);
                StringBuilder limitedContent = new StringBuilder();
                for (int i = 0; i < maxLines; i++) {
                    limitedContent.append(lines[i]).append("\n");
                }

                String result = limitedContent.toString();

                if (lines.length > limit) {
                    result += String.format("\n... (还有 %d 行未显示)", lines.length - limit);
                }

                return result;
            }

            // 限制大小（最多 50KB）
            if (content.length() > 50000) {
                content = content.substring(0, 50000);
                content += "\n... (文件过大，已截断)";
            }

            System.out.println("✅ 文件读取成功");
            return content;

        } catch (FileNotFoundException e) {
            return "❌ 错误: 文件不存在: " + path;
        } catch (IllegalArgumentException e) {
            return "❌ 安全错误: " + e.getMessage();
        } catch (Exception e) {
            return "❌ 读取文件失败: " + e.getMessage();
        }
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.core.SubAgentRunner;
import cn.edu.agent.tool.AgentTool;
import lombok.RequiredArgsConstructor;

import java.util.Map;

@RequiredArgsConstructor
public class TaskTool implements AgentTool {
    private final SubAgentRunner subAgentRunner;

    @Override
    public String getName() {
        return "task";
    }

    @Override
    public String getDescription() {
        return "Spawn a subagent with a fresh context to complete a subtask. \n"
                + "The subagent has access to all base tools (bash, read_file, write_file, edit_file, todo).\n"
                + "Only the final summary is returned. Use this for context-heavy subtasks to keep the main context clean.";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "prompt", Map.of(
                                "type", "string",
                                "description", "The task description for the subagent"
                        )
                ),
                "required", new String[]{"prompt"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) {
        String prompt = (String) input.get("prompt");
        if (prompt == null) {
            prompt = "";
        }
        String preview = prompt.length() <= 50 ? prompt : prompt.substring(0, 50);
        System.out.println("[TaskTool] Spawning subagent: " + preview + "...");
        return subAgentRunner.run(prompt);
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.todo.TodoManager;
import cn.edu.agent.tool.AgentTool;

import java.util.List;
import java.util.Map;

/**
 * Todo 工具：委托 {@link TodoManager} 管理带状态待办，并配合单 in_progress 约束。
 */
public class TodoTool implements AgentTool {

    private final TodoManager todoManager;

    public TodoTool(TodoManager todoManager) {
        this.todoManager = todoManager;
    }

    @Override
    public String getName() {
        return "todo";
    }

    @Override
    public String getDescription() {
        return "管理带状态的多步待办（pending / in_progress / done）。同一时间仅允许一项 in_progress。"
                + "用于规划与追踪任务，避免跳步或丢失进度。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "action", Map.of(
                                "type", "string",
                                "description", "操作类型：add、update、list、delete",
                                "enum", List.of("add", "update", "list", "delete")
                        ),
                        "id", Map.of(
                                "type", "string",
                                "description", "待办 ID（update / delete 必填）"
                        ),
                        "title", Map.of(
                                "type", "string",
                                "description", "标题（add 必填；update 时可选，用于改名）"
                        ),
                        "status", Map.of(
                                "type", "string",
                                "description", "状态（update 可选）：PENDING / IN_PROGRESS / COMPLETED（语义同 pending / in_progress / done）",
                                "enum", List.of("PENDING", "IN_PROGRESS", "COMPLETED")
                        )
                ),
                "required", new String[]{"action"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) throws Exception {
        String action = (String) input.get("action");
        if (action == null || action.trim().isEmpty()) {
            return "❌ 错误: 必须指定操作类型（action）";
        }
        System.out.println("\n[TodoTool] 📝 执行操作: " + action);
        try {
            return switch (action.toLowerCase()) {
                case "add" -> todoManager.add((String) input.get("title"));
                case "update" -> {
                    try {
                        yield todoManager.update(
                                (String) input.get("id"),
                                (String) input.get("status"),
                                (String) input.get("title"));
                    } catch (IllegalStateException e) {
                        yield "❌ 状态不合法: " + e.getMessage();
                    } catch (IllegalArgumentException e) {
                        yield "❌ " + e.getMessage();
                    }
                }
                case "list" -> todoManager.listRendered();
                case "delete" -> todoManager.delete((String) input.get("id"));
                default -> "❌ 错误: 未知的操作类型: " + action + "。支持的类型：add, update, list, delete";
            };
        } catch (Exception e) {
            return "❌ 执行失败: " + e.getMessage();
        }
    }
}

package cn.edu.agent.tool.impl;

import cn.edu.agent.tool.AgentTool;
import cn.edu.agent.tool.utils.WorkspaceEnv;

import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.StandardOpenOption;
import java.util.Map;

/**
 * WriteFile 工具 - 安全写入文件
 */
public class WriteFileTool implements AgentTool {

    @Override
    public String getName() {
        return "write_file";
    }

    @Override
    public String getDescription() {
        return "安全地写入文件内容。如果文件已存在会覆盖，如果不存在会创建。";
    }

    @Override
    public Map<String, Object> getInputSchema() {
        return Map.of(
                "type", "object",
                "properties", Map.of(
                        "path", Map.of(
                                "type", "string",
                                "description", "要写入的文件路径"
                        ),
                        "content", Map.of(
                                "type", "string",
                                "description", "要写入的文件内容"
                        )
            ),
        "required", new String[]{"path", "content"}
        );
    }

    @Override
    public String execute(Map<String, Object> input) throws Exception {
        String path = (String) input.get("path");
        String content = (String) input.get("content");

        if (path == null || path.trim().isEmpty()) {
            return "❌ 错误: 必须指定文件路径";
        }

        if (content == null) {
            return "❌ 错误: 必须指定文件内容";
        }

        System.out.println("\n[WriteFileTool] ✍️  写入文件: " + path);
        System.out.println("   工作目录: " + WorkspaceEnv.WORKDIR);
        System.out.println("   内容长度: " + content.length() + " 字符");

        try {
            // 使用 WorkspaceEnv 的 safePath
            Path safePath = WorkspaceEnv.safePath(path.trim());

            // 创建父目录（如果不存在）
            Path parentDir = safePath.getParent();
            if (parentDir != null && !Files.exists(parentDir)) {
                Files.createDirectories(parentDir);
                System.out.println("   已创建目录: " + parentDir);
            }

            // 写入文件
            Files.writeString(safePath, content, StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

            System.out.println("✅ 文件写入成功");
            return "✅ 文件已成功写入: " + path;

        } catch (IllegalArgumentException e) {
            return "❌ 安全错误: " + e.getMessage();
        } catch (Exception e) {
            return "❌ 写入文件失败: " + e.getMessage();
        }
    }
}
